#include <stdio.h>
#include <stdlib.h>

// Structure to represent a dish
typedef struct {
    int other_cook_time;
    int chef_time;
} Dish;

// Comparison function for sorting dishes
int compare_dishes(const void *a, const void *b) {
    Dish *dish1 = (Dish *)a;
    Dish *dish2 = (Dish *)b;
    return (dish2->other_cook_time - dish2->chef_time) - (dish1->other_cook_time - dish1->chef_time);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        Dish dishes[n];
        for (int i = 0; i < n; i++) {
            scanf("%d %d", &dishes[i].other_cook_time, &dishes[i].chef_time);
        }
        qsort(dishes, n, sizeof(Dish), compare_dishes);
        int chef_time = 0, assistant_time = 0;
        for (int i = 0; i < n; i++) {
            if (dishes[i].other_cook_time > dishes[i].chef_time * 2) {
                // Assign to other cook
                continue;
            } else if (chef_time <= assistant_time) {
                // Assign to chef
                chef_time += dishes[i].chef_time;
            } else {
                // Assign to assistant
                assistant_time += dishes[i].chef_time;
            }
        }
        printf("%d\n", (chef_time > assistant_time) ? chef_time : assistant_time);
    }
    return 0;
}

