import java.util.Arrays;
import java.util.Scanner;

public class Main {
    static class Dish implements Comparable<Dish> {
        int other_cook_time;
        int chef_time;
        Dish(int other_cook_time, int chef_time) {
            this.other_cook_time = other_cook_time;
            this.chef_time = chef_time;
        }
        @Override
        public int compareTo(Dish dish) {
            return Integer.compare(dish.other_cook_time - dish.chef_time, this.other_cook_time - this.chef_time);
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int n = scanner.nextInt();
            Dish[] dishes = new Dish[n];
            for (int i = 0; i < n; i++) {
                dishes[i] = new Dish(scanner.nextInt(), scanner.nextInt());
            }
            Arrays.sort(dishes);
            int chef_time = 0, assistant_time = 0;
            for (int i = 0; i < n; i++) {
                if (dishes[i].other_cook_time > dishes[i].chef_time * 2) {
                    // Assign to other cook
                    continue;
                } else if (chef_time <= assistant_time) {
                    // Assign to chef
                    chef_time += dishes[i].chef_time;
                } else {
                    // Assign to assistant
                    assistant_time += dishes[i].chef_time;
                }
            }
            System.out.println(Math.max(chef_time, assistant_time));
        }
    }
}

